const { QdrantClient } = require('@qdrant/js-client-rest');
async function check() {
  const client = new QdrantClient({ url: 'http://localhost:6333' });

  // List all collections
  try {
    const cols = await client.getCollections();
    console.log('Collections:', JSON.stringify(cols.collections?.map(c => c.name), null, 2));

    for (const col of (cols.collections || [])) {
      const info = await client.getCollection(col.name);
      const vecs = info.config.params.vectors;
      if (vecs) {
        console.log(\`Collection \${col.name} vectors:\`, JSON.stringify(vecs, null, 2));
      }
    }
  } catch(err) {
    console.error('Error:', err.message);
  }
}
check();
